+import Stripe from 'stripe';
+import { config } from '../config';
+import { logger } from '../logger';
+import { v4 as uuidv4 } from 'uuid';
+
+let stripeInstance: Stripe | null = null;
+
+export function getStripeClient(): Stripe {
+  if (!stripeInstance) {
+    if (!config.stripe.secretKey) {
+      throw new Error('STRIPE_SECRET_KEY is not configured');
+    }
+    stripeInstance = new Stripe(config.stripe.secretKey, {
+      apiVersion: '2024-02-29',
+      maxNetworkRetries: 3,
+      timeout: 10000,
+    });
+    logger.info('Stripe client initialized', { apiVersion: '2024-02-29' });
+  }
+  return stripeInstance;
+}
+
+export function generateIdempotencyKey(prefix: string): string {
+  return `${prefix}_${uuidv4()}`;
+}
+
+export async function validateStripeWebhookSignature(
+  payload: Buffer,
+  signature: string
+): Promise<Stripe.Event> {
+  const stripe = getStripeClient();
+  const webhookSecret = config.stripe.webhookSecret;
+  if (!webhookSecret) {
+    throw new Error('STRIPE_WEBHOOK_SECRET is not configured');
+  }
+  return stripe.webhooks.constructEventAsync(payload, signature, webhookSecret);
+}

