+import { Router, Request, Response } from 'express';
+import Stripe from 'stripe';
+import { validateStripeWebhookSignature } from '../../../payments/stripe-client';
+import { db } from '../../../db';
+import { logger } from '../../../logger';
+
+export const stripeWebhookRouter = Router();
+
+stripeWebhookRouter.post(
+  '/',
+  express.raw({ type: 'application/json' }),
+  async (req: Request, res: Response) => {
+    const signature = req.headers['stripe-signature'] as string;
+    let event: Stripe.Event;
+
+    try {
+      event = await validateStripeWebhookSignature(req.body, signature);
+    } catch (err) {
+      logger.warn('Invalid Stripe webhook signature', { err });
+      return res.status(400).json({ error: 'Invalid signature' });
+    }
+
+    // Idempotency: skip already-processed events
+    const existing = await db.webhookEvents.findFirst({ where: { stripeEventId: event.id } });
+    if (existing) {
+      return res.json({ received: true, duplicate: true });
+    }
+
+    await db.webhookEvents.create({ data: { stripeEventId: event.id, type: event.type } });
+
+    switch (event.type) {
+      case 'checkout.session.completed':
+        await handleCheckoutCompleted(event.data.object as Stripe.Checkout.Session);
+        break;
+      case 'payment_intent.succeeded':
+        await handlePaymentSucceeded(event.data.object as Stripe.PaymentIntent);
+        break;
+      case 'payment_intent.payment_failed':
+        await handlePaymentFailed(event.data.object as Stripe.PaymentIntent);
+        break;
+      case 'customer.subscription.updated':
+        await handleSubscriptionUpdated(event.data.object as Stripe.Subscription);
+        break;
+      case 'customer.subscription.deleted':
+        await handleSubscriptionDeleted(event.data.object as Stripe.Subscription);
+        break;
+      default:
+        logger.debug('Unhandled Stripe webhook event', { type: event.type });
+    }
+
+    res.json({ received: true });
+  }
+);

