+import Stripe from 'stripe';
+import { getStripeClient, generateIdempotencyKey } from './stripe-client';
+import { db } from '../db';
+
+export async function createSubscription(params: {
+  orgId: string;
+  userId: string;
+  priceId: string;
+  trialDays?: number;
+}): Promise<{ subscriptionId: string; clientSecret?: string }> {
+  const stripe = getStripeClient();
+
+  let customerId = await getOrCreateStripeCustomer(params.orgId);
+
+  const subscription = await stripe.subscriptions.create({
+    customer: customerId,
+    items: [{ price: params.priceId }],
+    trial_period_days: params.trialDays,
+    payment_behavior: 'default_incomplete',
+    payment_settings: { save_default_payment_method: 'on_subscription' },
+    expand: ['latest_invoice.payment_intent'],
+    metadata: { orgId: params.orgId, userId: params.userId },
+  }, { idempotencyKey: generateIdempotencyKey(`sub_create_${params.orgId}`) });
+
+  await db.subscriptions.upsert({
+    where: { orgId: params.orgId },
+    create: {
+      orgId: params.orgId,
+      stripeSubscriptionId: subscription.id,
+      stripeCustomerId: customerId,
+      status: subscription.status,
+      priceId: params.priceId,
+      currentPeriodEnd: new Date(subscription.current_period_end * 1000),
+    },
+    update: {
+      stripeSubscriptionId: subscription.id,
+      status: subscription.status,
+    },
+  });
+
+  const invoice = subscription.latest_invoice as Stripe.Invoice;
+  const paymentIntent = invoice?.payment_intent as Stripe.PaymentIntent;
+
+  return {
+    subscriptionId: subscription.id,
+    clientSecret: paymentIntent?.client_secret ?? undefined,
+  };
+}
+
+export async function cancelSubscription(
+  orgId: string,
+  immediately = false
+): Promise<void> {
+  const sub = await db.subscriptions.findFirst({ where: { orgId, status: { not: 'canceled' } } });
+  if (!sub) throw new Error('No active subscription found');
+
+  const stripe = getStripeClient();
+  await stripe.subscriptions.update(sub.stripeSubscriptionId, {
+    cancel_at_period_end: !immediately,
+    ...(immediately ? { cancellation_details: { comment: 'Immediate cancellation requested' } } : {}),
+  });
+}

