+import { Router, Request, Response } from 'express';
+import { requireAuth } from '../../../middleware/auth';
+import { db } from '../../../db';
+import { z } from 'zod';
+
+export const historyRouter = Router();
+
+const QuerySchema = z.object({
+  limit: z.coerce.number().int().min(1).max(100).default(20),
+  after: z.string().optional(),
+  status: z.enum(['pending', 'succeeded', 'failed', 'refunded']).optional(),
+  processor: z.enum(['stripe', 'paypal']).optional(),
+  startDate: z.string().datetime().optional(),
+  endDate: z.string().datetime().optional(),
+});
+
+historyRouter.get('/', requireAuth, async (req: Request, res: Response) => {
+  const query = QuerySchema.parse(req.query);
+  const orgId = req.user!.organizationId;
+
+  const where: any = { orgId };
+  if (query.status) where.status = query.status;
+  if (query.processor) where.processor = query.processor;
+  if (query.startDate || query.endDate) {
+    where.createdAt = {};
+    if (query.startDate) where.createdAt.gte = new Date(query.startDate);
+    if (query.endDate) where.createdAt.lte = new Date(query.endDate);
+  }
+  if (query.after) where.id = { gt: query.after };
+
+  const payments = await db.payments.findMany({
+    where,
+    take: query.limit + 1,
+    orderBy: { createdAt: 'desc' },
+  });
+
+  const hasMore = payments.length > query.limit;
+  const items = hasMore ? payments.slice(0, -1) : payments;
+
+  res.json({
+    data: items,
+    pagination: {
+      hasMore,
+      nextCursor: hasMore ? items[items.length - 1].id : null,
+    },
+  });
+});

