+import { WebSocketServer, WebSocket } from 'ws';
+import { IncomingMessage } from 'http';
+import { verifyJwt } from '../auth/jwt';
+import { logger } from '../logger';
+
+interface AuthenticatedSocket extends WebSocket {
+  userId: string;
+  orgId: string;
+  isAlive: boolean;
+}
+
+const userConnections = new Map<string, Set<AuthenticatedSocket>>();
+
+export function createWsServer(httpServer: any): WebSocketServer {
+  const wss = new WebSocketServer({ server: httpServer, path: '/ws' });
+
+  wss.on('connection', async (ws: AuthenticatedSocket, req: IncomingMessage) => {
+    try {
+      const token = extractTokenFromRequest(req);
+      const payload = await verifyJwt(token);
+      ws.userId = payload.sub;
+      ws.orgId = payload.orgId;
+      ws.isAlive = true;
+    } catch (err) {
+      ws.close(4001, 'Unauthorized');
+      return;
+    }
+
+    registerConnection(ws);
+
+    ws.on('pong', () => { ws.isAlive = true; });
+    ws.on('close', () => deregisterConnection(ws));
+    ws.on('error', (err) => {
+      logger.error('WebSocket error', { userId: ws.userId, err });
+      deregisterConnection(ws);
+    });
+
+    ws.send(JSON.stringify({ type: 'connected', userId: ws.userId }));
+  });
+
+  // Heartbeat interval to detect dead connections
+  const heartbeatInterval = setInterval(() => {
+    wss.clients.forEach((ws: any) => {
+      if (!ws.isAlive) return ws.terminate();
+      ws.isAlive = false;
+      ws.ping();
+    });
+  }, 30000);
+
+  wss.on('close', () => clearInterval(heartbeatInterval));
+  return wss;
+}
+
+export function sendToUser(userId: string, event: object): number {
+  const sockets = userConnections.get(userId);
+  if (!sockets?.size) return 0;
+  const message = JSON.stringify(event);
+  let sent = 0;
+  for (const ws of sockets) {
+    if (ws.readyState === WebSocket.OPEN) {
+      ws.send(message);
+      sent++;
+    }
+  }
+  return sent;
+}
+
+function registerConnection(ws: AuthenticatedSocket): void {
+  if (!userConnections.has(ws.userId)) userConnections.set(ws.userId, new Set());
+  userConnections.get(ws.userId)!.add(ws);
+}
+
+function deregisterConnection(ws: AuthenticatedSocket): void {
+  userConnections.get(ws.userId)?.delete(ws);
+}

