+import { sendToUser } from './ws-server';
+import { db } from '../db';
+import { NotificationEvent, NotificationEventType } from './types';
+import { v4 as uuidv4 } from 'uuid';
+
+export async function deliverNotification(
+  userId: string,
+  orgId: string,
+  type: NotificationEventType,
+  payload: {
+    title: string;
+    body: string;
+    metadata?: Record<string, unknown>;
+  }
+): Promise<void> {
+  const event: NotificationEvent = {
+    id: uuidv4(),
+    type,
+    userId,
+    orgId,
+    ...payload,
+    createdAt: new Date().toISOString(),
+  };
+
+  // Persist for offline delivery
+  await db.notifications.create({ data: event });
+
+  // Attempt real-time delivery
+  const delivered = sendToUser(userId, event);
+
+  if (delivered === 0) {
+    // Mark as unread; user will fetch on next login
+    await db.notifications.update({ where: { id: event.id }, data: { readAt: null } });
+  }
+}

