+import EventEmitter from 'eventemitter3';
+import { NotificationEvent } from '../notifications/types';
+
+const MAX_RECONNECT_DELAY_MS = 30_000;
+const BASE_RECONNECT_DELAY_MS = 250;
+
+export class NotificationsClient extends EventEmitter {
+  private ws: WebSocket | null = null;
+  private reconnectAttempts = 0;
+  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
+  private shouldReconnect = true;
+
+  constructor(private readonly getAuthToken: () => Promise<string>) {
+    super();
+  }
+
+  async connect(): Promise<void> {
+    this.shouldReconnect = true;
+    await this._connect();
+  }
+
+  disconnect(): void {
+    this.shouldReconnect = false;
+    if (this.reconnectTimer) clearTimeout(this.reconnectTimer);
+    this.ws?.close(1000, 'Client disconnect');
+  }
+
+  private async _connect(): Promise<void> {
+    const token = await this.getAuthToken();
+    const url = `${location.origin.replace('http', 'ws')}/ws?token=${token}`;
+    this.ws = new WebSocket(url);
+
+    this.ws.onopen = () => {
+      this.reconnectAttempts = 0;
+      this.emit('connected');
+    };
+
+    this.ws.onmessage = (event) => {
+      try {
+        const notification: NotificationEvent = JSON.parse(event.data);
+        this.emit('notification', notification);
+        this.emit(notification.type, notification);
+      } catch { /* ignore malformed messages */ }
+    };
+
+    this.ws.onclose = () => {
+      this.emit('disconnected');
+      if (this.shouldReconnect) this._scheduleReconnect();
+    };
+  }
+
+  private _scheduleReconnect(): void {
+    const jitter = Math.random() * 100;
+    const delay = Math.min(
+      BASE_RECONNECT_DELAY_MS * Math.pow(2, this.reconnectAttempts) + jitter,
+      MAX_RECONNECT_DELAY_MS
+    );
+    this.reconnectAttempts++;
+    this.reconnectTimer = setTimeout(() => this._connect(), delay);
+  }
+}

