+import { Request, Response, NextFunction } from 'express';
+import { LRUCache } from 'lru-cache';
+import { redis } from '../redis';
+import { logger } from '../logger';
+
+interface BucketState {
+  tokens: number;
+  lastRefillAt: number;
+}
+
+const localCache = new LRUCache<string, BucketState>({ max: 50_000 });
+
+async function getBucketState(key: string, capacity: number): Promise<BucketState> {
+  if (redis?.isReady) {
+    const raw = await redis.get(`rl:${key}`);
+    return raw ? JSON.parse(raw) : { tokens: capacity, lastRefillAt: Date.now() };
+  }
+  return localCache.get(key) ?? { tokens: capacity, lastRefillAt: Date.now() };
+}
+
+async function saveBucketState(key: string, state: BucketState, ttlMs: number): Promise<void> {
+  if (redis?.isReady) {
+    await redis.set(`rl:${key}`, JSON.stringify(state), { PX: ttlMs });
+    return;
+  }
+  localCache.set(key, state, { ttl: ttlMs });
+}
+
+export function rateLimitMiddleware(opts: {
+  capacity: number;
+  refillRate: number;
+  refillIntervalMs: number;
+  keyFn?: (req: Request) => string;
+}) {
+  return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
+    const key = opts.keyFn?.(req) ?? (req.user?.organizationId ?? req.ip);
+    const now = Date.now();
+
+    const state = await getBucketState(key, opts.capacity);
+    const elapsed = now - state.lastRefillAt;
+    const refills = Math.floor(elapsed / opts.refillIntervalMs) * opts.refillRate;
+    state.tokens = Math.min(opts.capacity, state.tokens + refills);
+    state.lastRefillAt = state.tokens < opts.capacity ? state.lastRefillAt + Math.floor(elapsed / opts.refillIntervalMs) * opts.refillIntervalMs : now;
+
+    if (state.tokens < 1) {
+      const retryAfterMs = opts.refillIntervalMs - (now - state.lastRefillAt);
+      res.setHeader('Retry-After', Math.ceil(retryAfterMs / 1000).toString());
+      res.status(429).json({ error: 'Rate limit exceeded', retryAfterMs });
+      return;
+    }
+
+    state.tokens -= 1;
+    await saveBucketState(key, state, opts.capacity * opts.refillIntervalMs);
+    next();
+  };
+}

